# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.*
import java.util.concurrent.TimeUnit

class IoTHttpClient {
    private val client: OkHttpClient
    
    init {
        client = OkHttpClient.Builder()
            .connectTimeout(10, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .build()
    }
    
    fun makeRequest(url: String, method: String = "GET", requestBody: RequestBody? = null): Response {
        val requestBuilder = Request.Builder()
            .url(url)
        
        when (method.uppercase()) {
            "GET" -> requestBuilder.get()
            "POST" -> requestBuilder.post(requestBody ?: RequestBody.create("", MediaType.parse("application/json")))
            "PUT" -> requestBuilder.put(requestBody ?: RequestBody.create("", MediaType.parse("application/json")))
            "DELETE" -> requestBuilder.delete()
        }
        
        val request = requestBuilder.build()
        return client.newCall(request).execute()
    }
    
    fun getDeviceData(deviceIp: String, port: Int = 80, endpoint: String = "/"): Response {
        val url = "http://$deviceIp:$port$endpoint"
        return makeRequest(url, "GET")
    }
    
    fun sendDeviceCommand(deviceIp: String, port: Int = 80, endpoint: String = "/", command: String): Response {
        val url = "http://$deviceIp:$port$endpoint"
        val body = RequestBody.create(command, MediaType.parse("application/json"))
        return makeRequest(url, "POST", body)
    }
    
    fun callCloudApi(endpoint: String, method: String = "GET", data: String? = null): Response {
        val url = "https://api.example.com$endpoint"
        val requestBody = data?.let { RequestBody.create(it, MediaType.parse("application/json")) }
        return makeRequest(url, method, requestBody)
    }
}